// 兩個手足元件各自管理自己的 state，彼此看不到對方 → 無法同步
// 解法：把溫度這份 state 往上移到共同的父層
function Calculator() {
  const [celsius, setCelsius] = useState(0);
  return (
    <>
      <TemperatureInput scale="c" value={celsius} onChange={setCelsius} />
      <TemperatureInput scale="f" value={celsius * 9/5 + 32} onChange={(f) => setCelsius((f - 32) * 5/9)} />
    </>
  );
}

function NicknameEditor({ initialName }) {
  const [name, setName] = useState(initialName); // 只在第一次渲染生效
  return <input value={name} onChange={(e) => setName(e.target.value)} />;
}

